import React, { useEffect, useMemo, useState } from 'react'
import { pondService, sensorService } from '../../services/api'
import '../../styles/dashboard.css'
import '../../styles/technician/technician-sensors.css'

const emptyForm = {
  pondId: '',
  sensorName: '',
  sensorType: '',
  serialNumber: '',
  status: 'ACTIVE',
}

const TechnicianSensors = () => {
  const [sensors, setSensors] = useState([])
  const [ponds, setPonds] = useState([])
  const [searchTerm, setSearchTerm] = useState('')
  const [pondFilter, setPondFilter] = useState('ALL')
  const [typeFilter, setTypeFilter] = useState('ALL')
  const [statusFilter, setStatusFilter] = useState('ALL')
  const [pageSize, setPageSize] = useState(10)
  const [currentPage, setCurrentPage] = useState(1)
  const [loading, setLoading] = useState(true)
  const [saving, setSaving] = useState(false)
  const [error, setError] = useState('')
  const [showModal, setShowModal] = useState(false)
  const [form, setForm] = useState(emptyForm)
  const [editingId, setEditingId] = useState(null)

  useEffect(() => {
    fetchData()
  }, [])

  const fetchData = async () => {
    try {
      setLoading(true)
      const [sensorRes, pondRes] = await Promise.all([
        sensorService.getAllSensors(),
        pondService.getAllPonds(),
      ])
      setSensors(sensorRes?.data?.data || [])
      setPonds(pondRes?.data?.data || [])
      setError('')
    } catch (err) {
      setError(err?.response?.data?.message || 'Không tải được dữ liệu cảm biến')
    } finally {
      setLoading(false)
    }
  }

  const pondOptions = useMemo(() => ponds, [ponds])

  const normalizeType = (type) => String(type || '').trim().toLowerCase()

  const normalizeStatus = (status) => {
    const value = String(status || '').trim().toUpperCase()
    if (['ACTIVE', 'HOAT_DONG', 'ONLINE'].includes(value)) return 'ACTIVE'
    if (['INACTIVE', 'OFFLINE', 'NGOAI_TUYEN'].includes(value)) return 'INACTIVE'
    return value || 'INACTIVE'
  }

  const getStatusLabel = (status) => {
    switch (normalizeStatus(status)) {
      case 'ACTIVE':
        return 'Hoạt động'
      case 'INACTIVE':
        return 'Ngoại tuyến'
      default:
        return 'Ngoại tuyến'
    }
  }

  const getTypeLabel = (sensorType) => {
    switch (normalizeType(sensorType)) {
      case 'ph':
        return 'Độ pH'
      case 'temperature':
        return 'Nhiệt độ nước'
      case 'dissolved oxygen':
        return 'Oxy hòa tan'
      case 'salinity':
        return 'Độ mặn'
      case 'water level':
        return 'Mực nước'
      default:
        return sensorType || '-'
    }
  }
  
  // compute per-type latest metrics (average of current_value for sensors of that type)
  const recentMetrics = useMemo(() => {
    const types = ['ph', 'temperature', 'dissolved oxygen', 'salinity', 'water level']
    const map = {}
    types.forEach((t) => {
      const items = sensors.filter((s) => normalizeType(s.sensor_type) === normalizeType(t) && s.current_value !== null && s.current_value !== undefined && !Number.isNaN(Number(s.current_value)))
      if (items.length === 0) {
        map[t] = null
      } else {
        const sum = items.reduce((acc, it) => acc + Number(it.current_value), 0)
        map[t] = sum / items.length
      }
    })
    return map
  }, [sensors])

  const [isLivePaused, setIsLivePaused] = useState(false)

  const handleToggleLive = () => {
    setIsLivePaused((p) => !p)
  }

  const handleExportData = () => {
    const rows = filteredSensors.map((s) => ({
      sensor_id: s.sensor_id,
      sensor_name: s.sensor_name,
      pond: getPondName(s.pond_id),
      type: s.sensor_type,
      value: s.current_value ?? '',
      status: s.status ?? '',
      last_updated: s.last_updated ?? '',
    }))

    const header = Object.keys(rows[0] || {}).join(',')
    const csv = [header]
      .concat(rows.map((r) => Object.values(r).map((v) => `"${String(v).replace(/"/g, '""')}"`).join(',')))
      .join('\n')

    const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' })
    const url = URL.createObjectURL(blob)
    const a = document.createElement('a')
    a.href = url
    a.download = `sensors_export_${new Date().toISOString()}.csv`
    a.click()
    URL.revokeObjectURL(url)
  }

  const getSensorBadge = (sensorType) => {
    switch (normalizeType(sensorType)) {
      case 'ph':
        return 'pH'
      case 'temperature':
        return '°C'
      case 'dissolved oxygen':
        return 'O2'
      case 'salinity':
        return 'Na'
      case 'water level':
        return 'WL'
      default:
        return 'SN'
    }
  }

  const getDisplayValue = (sensor) => {
    const value = sensor.current_value
    if (value === null || value === undefined || Number.isNaN(Number(value))) return '-'

    const num = Number(value)
    const type = normalizeType(sensor.sensor_type)
    if (type === 'temperature') return `${num.toFixed(1)}°C`
    if (type === 'dissolved oxygen') return `${num.toFixed(1)} mg/L`
    if (type === 'ph') return `${num.toFixed(1)} pH`
    if (type === 'salinity') return `${num.toFixed(1)} ppt`
    if (type === 'water level') return `${num.toFixed(1)} m`
    return `${num.toFixed(1)}`
  }

  const formatDateTime = (raw) => {
    if (!raw) return '-'
    const d = new Date(raw)
    if (Number.isNaN(d.getTime())) return '-'
    return d.toLocaleString('vi-VN', {
      hour: '2-digit',
      minute: '2-digit',
      day: '2-digit',
      month: '2-digit',
      year: 'numeric',
    })
  }

  const resetToFirstPage = () => {
    setCurrentPage(1)
  }

  const filteredSensors = useMemo(() => {
    return sensors.filter((sensor) => {
      const normalizedSearch = searchTerm.trim().toLowerCase()
      const searchMatched =
        !normalizedSearch ||
        String(sensor.sensor_name || '').toLowerCase().includes(normalizedSearch) ||
        String(sensor.serial_number || '').toLowerCase().includes(normalizedSearch) ||
        String(sensor.sensor_id || '').toLowerCase().includes(normalizedSearch)

      const sensorPondId = String(sensor.pond_id || '')
      const pondMatched = pondFilter === 'ALL' || String(pondFilter) === sensorPondId

      const sensorType = normalizeType(sensor.sensor_type)
      const typeMatched = typeFilter === 'ALL' || sensorType === normalizeType(typeFilter)

      const statusMatched = statusFilter === 'ALL' || normalizeStatus(sensor.status) === statusFilter

      return searchMatched && pondMatched && typeMatched && statusMatched
    })
  }, [sensors, searchTerm, pondFilter, typeFilter, statusFilter])

  const stats = useMemo(() => {
    const total = sensors.length
    const active = sensors.filter((item) => normalizeStatus(item.status) === 'ACTIVE').length
    const inactive = sensors.filter((item) => normalizeStatus(item.status) === 'INACTIVE').length
    return { total, active, inactive }
  }, [sensors])

  const totalPages = Math.max(1, Math.ceil(filteredSensors.length / pageSize))
  const safePage = Math.min(currentPage, totalPages)
  const startIndex = (safePage - 1) * pageSize
  const endIndex = Math.min(startIndex + pageSize, filteredSensors.length)
  const paginatedSensors = filteredSensors.slice(startIndex, endIndex)

  useEffect(() => {
    if (currentPage > totalPages) {
      setCurrentPage(totalPages)
    }
  }, [currentPage, totalPages])

  const getPondName = (pondId) => {
    if (!pondId) return '-'
    const found = pondOptions.find((pond) => String(pond.pond_id) === String(pondId))
    return found ? `${found.pond_code || ''} ${found.pond_name || ''}`.trim() : '-'
  }

  const openCreateModal = () => {
    setForm(emptyForm)
    setEditingId(null)
    setShowModal(true)
  }

  const openEditModal = (sensor) => {
    setEditingId(sensor.sensor_id)
    setForm({
      pondId: sensor.pond_id,
      sensorName: sensor.sensor_name,
      sensorType: sensor.sensor_type,
      serialNumber: sensor.serial_number || '',
      status: sensor.status || 'ACTIVE',
    })
    setShowModal(true)
  }

  const handleChange = (field, value) => {
    setForm((prev) => {
      const next = { ...prev, [field]: value }

      // Tự động sinh mã seri khi đã chọn ao và loại cảm biến
      if ((field === 'pondId' || field === 'sensorType')) {
        const pond = pondOptions.find((p) => String(p.pond_id) === String(next.pondId))
        const pondCode = pond ? pond.pond_code : null

        const typeMap = {
          pH: 'PH',
          temperature: 'TEMP',
          'dissolved oxygen': 'DO',
          salinity: 'SAL',
          'water level': 'LEVEL',
        }

        const t = (next.sensorType || '').toString()
        const typeCode = typeMap[t]
        if (typeCode && pondCode) {
          next.serialNumber = `${typeCode}-${pondCode}`
        } else if (typeCode && next.pondId) {
          next.serialNumber = `${typeCode}-${next.pondId}`
        }
      }

      return next
    })
  }

  const handleSubmit = async (event) => {
    event.preventDefault()
    try {
      setSaving(true)
      if (editingId) {
        await sensorService.updateSensor(editingId, {
          pond_id: Number(form.pondId),
          sensor_name: form.sensorName.trim(),
          sensor_type: form.sensorType.trim(),
          serial_number: form.serialNumber.trim() || null,
          status: form.status,
        })
      } else {
        await sensorService.createSensor({
          pond_id: Number(form.pondId),
          sensor_name: form.sensorName.trim(),
          sensor_type: form.sensorType.trim(),
          serial_number: form.serialNumber.trim() || null,
          status: form.status,
        })
      }
      setShowModal(false)
      setForm(emptyForm)
      setEditingId(null)
      await fetchData()
    } catch (err) {
      setError(err?.response?.data?.message || 'Không tạo được cảm biến')
    } finally {
      setSaving(false)
    }
  }

  const handleDelete = async (sensorId) => {
    if (!window.confirm('Bạn có chắc muốn xóa cảm biến này?')) return
    try {
      await sensorService.deleteSensor(sensorId)
      await fetchData()
    } catch (err) {
      setError(err?.response?.data?.message || 'Không xóa được cảm biến')
    }
  }

  return (
    <div className="dashboard technician-sensors">
      <div className="technician-sensors__title-block">
        <h2>Quản lý cảm biến</h2>
        <p>Theo dõi và quản lý các cảm biến trong hệ thống ao tôm</p>
      </div>

      {error && <div className="alert alert-error">{error}</div>}

      <section className="technician-sensors__stats-grid">
        <article className="technician-sensors__stat-card">
          <span className="technician-sensors__stat-icon technician-sensors__stat-icon--blue">◈</span>
          <div>
            <p className="technician-sensors__stat-label">Tổng cảm biến</p>
            <h3 className="technician-sensors__stat-value">{stats.total}</h3>
          </div>
        </article>
        <article className="technician-sensors__stat-card">
          <span className="technician-sensors__stat-icon technician-sensors__stat-icon--green">◉</span>
          <div>
            <p className="technician-sensors__stat-label">Cảm biến đang hoạt động</p>
            <h3 className="technician-sensors__stat-value">{stats.active}</h3>
          </div>
        </article>
        <article className="technician-sensors__stat-card">
          <span className="technician-sensors__stat-icon technician-sensors__stat-icon--red">✕</span>
          <div>
            <p className="technician-sensors__stat-label">Cảm biến ngoại tuyến</p>
            <h3 className="technician-sensors__stat-value">{stats.inactive}</h3>
          </div>
        </article>
      </section>

      {/* Mini metric row (per-type quick cards) */}
      <section className="technician-sensors__mini-metrics">
        <div className="technician-sensors__mini-card">
          <div className="mini-card-value">{recentMetrics['temperature'] !== null && recentMetrics['temperature'] !== undefined ? `${recentMetrics['temperature'].toFixed(1)}°C` : '-'} </div>
          <div className="mini-card-label">Nhiệt độ</div>
        </div>
        <div className="technician-sensors__mini-card">
          <div className="mini-card-value">{recentMetrics['ph'] !== null && recentMetrics['ph'] !== undefined ? `${recentMetrics['ph'].toFixed(1)} pH` : '-'} </div>
          <div className="mini-card-label">pH</div>
        </div>
        <div className="technician-sensors__mini-card">
          <div className="mini-card-value">{recentMetrics['dissolved oxygen'] !== null && recentMetrics['dissolved oxygen'] !== undefined ? `${recentMetrics['dissolved oxygen'].toFixed(1)} mg/L` : '-'} </div>
          <div className="mini-card-label">DO</div>
        </div>
        <div className="technician-sensors__mini-card">
          <div className="mini-card-value">{recentMetrics['salinity'] !== null && recentMetrics['salinity'] !== undefined ? `${recentMetrics['salinity'].toFixed(1)} ppt` : '-'} </div>
          <div className="mini-card-label">Độ mặn</div>
        </div>
        <div className="technician-sensors__mini-card">
          <div className="mini-card-value">{recentMetrics['water level'] !== null && recentMetrics['water level'] !== undefined ? `${recentMetrics['water level'].toFixed(1)} m` : '-'} </div>
          <div className="mini-card-label">Mực nước</div>
        </div>
      </section>

      {/* Recent chart placeholder */}
      <section className="technician-sensors__recent-chart">
        <div className="technician-sensors__recent-chart-inner">Recent Sensor Data (chart placeholder)</div>
      </section>

      <section className="technician-sensors__panel">
        <div className="technician-sensors__toolbar">
          <div className="technician-sensors__search-wrap">
            <span className="technician-sensors__search-icon">⌕</span>
            <input
              type="text"
              value={searchTerm}
              placeholder="Tìm kiếm cảm biến..."
              onChange={(e) => {
                setSearchTerm(e.target.value)
                resetToFirstPage()
              }}
            />
          </div>

          <select
            value={pondFilter}
            onChange={(e) => {
              setPondFilter(e.target.value)
              resetToFirstPage()
            }}
          >
            <option value="ALL">Tất cả ao</option>
            {pondOptions.map((pond) => (
              <option key={pond.pond_id} value={pond.pond_id}>
                {pond.pond_code} - {pond.pond_name}
              </option>
            ))}
          </select>

          <select
            value={typeFilter}
            onChange={(e) => {
              setTypeFilter(e.target.value)
              resetToFirstPage()
            }}
          >
            <option value="ALL">Tất cả loại cảm biến</option>
            <option value="pH">Độ pH</option>
            <option value="temperature">Nhiệt độ</option>
            <option value="dissolved oxygen">Oxy hòa tan</option>
            <option value="salinity">Độ mặn</option>
            <option value="water level">Mực nước</option>
          </select>

          <select
            value={statusFilter}
            onChange={(e) => {
              setStatusFilter(e.target.value)
              resetToFirstPage()
            }}
          >
            <option value="ALL">Tất cả trạng thái</option>
            <option value="ACTIVE">Hoạt động</option>
            <option value="INACTIVE">Ngoại tuyến</option>
          </select>

          <button className="btn" onClick={handleExportData} title="Export data">Export data</button>
          <button className="btn btn-secondary" onClick={handleToggleLive} title="Pause/Resume live updates">{isLivePaused ? 'Resume Live updates' : 'Pause Live updates'}</button>
          <button className="btn btn-primary technician-sensors__create-btn" onClick={openCreateModal}>
            + Thêm cảm biến
          </button>
        </div>

        <div className="table-wrapper">
          <table className="technician-sensors__table">
            <thead>
              <tr>
                <th>Avatar</th>
                <th>Tên cảm biến</th>
                <th>Loại cảm biến</th>
                <th>Ao nuôi</th>
                <th>Giá trị hiện tại</th>
                <th>Trạng thái</th>
                <th>Lần cập nhật cuối</th>
                <th>Actions</th>
              </tr>
            </thead>
            <tbody>
              {loading ? (
                <tr>
                  <td colSpan="8" className="technician-sensors__empty-row">Đang tải dữ liệu...</td>
                </tr>
              ) : paginatedSensors.length === 0 ? (
                <tr>
                  <td colSpan="8" className="technician-sensors__empty-row">Không có cảm biến phù hợp bộ lọc</td>
                </tr>
              ) : (
                paginatedSensors.map((sensor) => (
                  <tr key={sensor.sensor_id}>
                    <td>
                      <span className="technician-sensors__avatar-chip">{getSensorBadge(sensor.sensor_type)}</span>
                    </td>
                    <td>{sensor.sensor_name || '-'}</td>
                    <td>{getTypeLabel(sensor.sensor_type)}</td>
                    <td>{getPondName(sensor.pond_id)}</td>
                    <td className="technician-sensors__value-cell">{getDisplayValue(sensor)}</td>
                    <td>
                      <span className={`technician-sensors__status technician-sensors__status--${normalizeStatus(sensor.status).toLowerCase()}`}>
                        {getStatusLabel(sensor.status)}
                      </span>
                    </td>
                    <td>{formatDateTime(sensor.last_updated)}</td>
                    <td>
                      <div className="technician-sensors__table-actions">
                        <button className="btn btn-sm btn-secondary" onClick={() => openEditModal(sensor)} title="Sửa">
                          ✎
                        </button>
                        <button className="btn btn-sm btn-danger" onClick={() => handleDelete(sensor.sensor_id)} title="Xóa">
                          🗑
                        </button>
                      </div>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>

        <div className="technician-sensors__pagination">
          <div className="technician-sensors__pagination-left">
            <label htmlFor="technicianSensorPageSize">Items per page:</label>
            <select
              id="technicianSensorPageSize"
              value={pageSize}
              onChange={(e) => {
                setPageSize(Number(e.target.value))
                setCurrentPage(1)
              }}
            >
              <option value={10}>10</option>
              <option value={20}>20</option>
              <option value={50}>50</option>
            </select>
            <span>
              {filteredSensors.length === 0 ? 0 : startIndex + 1}-{endIndex} of {filteredSensors.length}
            </span>
          </div>

          <div className="technician-sensors__pagination-right">
            <button
              type="button"
              className="btn btn-sm btn-secondary"
              onClick={() => setCurrentPage((prev) => Math.max(1, prev - 1))}
              disabled={safePage <= 1}
            >
              ‹
            </button>
            <span className="technician-sensors__page-pill">{safePage}</span>
            <button
              type="button"
              className="btn btn-sm btn-secondary"
              onClick={() => setCurrentPage((prev) => Math.min(totalPages, prev + 1))}
              disabled={safePage >= totalPages}
            >
              ›
            </button>
          </div>
        </div>
      </section>

      {showModal && (
        <div className="modal" onClick={() => setShowModal(false)}>
          <div className="modal-content technician-sensors__modal-content" onClick={(e) => e.stopPropagation()}>
            <h3 className="technician-sensors__modal-title">{editingId ? 'Sửa cảm biến' : 'Thêm cảm biến mới'}</h3>
            <form onSubmit={handleSubmit}>
              <div className="form-group">
                <label>Ao nuôi</label>
                <select className="input" value={form.pondId} onChange={(e) => handleChange('pondId', e.target.value)} required>
                  <option value="">-- Chọn ao --</option>
                  {pondOptions.map((pond) => (
                    <option key={pond.pond_id} value={pond.pond_id}>
                      {pond.pond_code} - {pond.pond_name}
                    </option>
                  ))}
                </select>
              </div>

              <div className="form-group">
                <label>Tên cảm biến</label>
                <input className="input" value={form.sensorName} onChange={(e) => handleChange('sensorName', e.target.value)} required />
              </div>

              <div className="technician-sensors__form-grid">
                <div className="form-group">
                  <label>Loại cảm biến</label>
                  <select className="input" value={form.sensorType} onChange={(e) => handleChange('sensorType', e.target.value)} required>
                    <option value="">-- Chọn loại --</option>
                    <option value="pH">pH</option>
                    <option value="temperature">Nhiệt độ</option>
                    <option value="dissolved oxygen">Oxy hoà tan</option>
                    <option value="salinity">Độ mặn</option>
                    <option value="water level">Mực nước</option>
                  </select>
                </div>
                <div className="form-group">
                  <label>Serial number (tự sinh)</label>
                  <input className="input" value={form.serialNumber} onChange={(e) => handleChange('serialNumber', e.target.value)} placeholder="Sẽ tự điền khi chọn ao và loại" />
                </div>
              </div>

              <div className="form-group">
                <label>Trạng thái</label>
                <select className="input" value={form.status} onChange={(e) => handleChange('status', e.target.value)}>
                  <option value="ACTIVE">ACTIVE</option>
                  <option value="INACTIVE">INACTIVE</option>
                </select>
              </div>

              <div className="technician-sensors__form-buttons">
                <button type="submit" className="btn btn-primary" disabled={saving}>
                  💾 {saving ? 'Đang lưu' : 'Lưu cảm biến'}
                </button>
                <button type="button" className="btn btn-secondary" onClick={() => setShowModal(false)}>
                  ❌ Hủy
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  )
}

export default TechnicianSensors
